func profileRegressionsBasePath(projectID int64) string {
	return "/projects/" + strconv.FormatInt(projectID, 10) + "/profile-regressions"
}

func profileRegStatusURL(projectID int64, status string) string {
	if status == "" {
		return profileRegressionsBasePath(projectID)
	}
	return profileRegressionsBasePath(projectID) + "?status=" + status
}

// profileRegShare — доля в процентах (0.2 → "20.0%").
func profileRegShare(share float64) string {
	return strconv.FormatFloat(share*100, 'f', 1, 64) + "%"
}

// profileRegRange — «база → пик» долей.
func profileRegRange(r profile.Regression) string {
	return profileRegShare(r.BaselineShare) + " → " + profileRegShare(r.PeakShare)
}

// profileRegIncreasePct — рост от ПИКА над базой в процентах (как этап 4). База
// <= 0 → «—».
func profileRegIncreasePct(r profile.Regression) string {
	if r.BaselineShare <= 0 {
		return "—"
	}
	pct := (r.PeakShare - r.BaselineShare) / r.BaselineShare * 100
	rounded := int64(math.Round(pct))
	sign := "+"
	if rounded < 0 {
		sign = ""
	}
	return sign + strconv.FormatInt(rounded, 10) + "%"
}

func profileRegDuration(r profile.Regression) string {
	if r.ResolvedAt == nil {
		return "ongoing"
	}
	return r.ResolvedAt.Sub(r.StartedAt).String()
}

func profileRegServiceType(r profile.Regression) string {
	return r.Service + " · " + r.ProfileType
}

